import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { Container, Row, Col, Form, Alert } from 'react-bootstrap';
import { toast } from 'react-toastify';
import { userAPI, orderAPI } from '../services/api';
import { useCart } from '../context/CartContext';

const CheckoutPage = () => {
  const [addresses, setAddresses] = useState([]);
  const [selectedAddress, setSelectedAddress] = useState('');
  const [paymentMethod, setPaymentMethod] = useState('COD');
  const [loading, setLoading] = useState(false);
  const [newAddress, setNewAddress] = useState({ name: '', phone: '', addressLine1: '', city: '', state: '', pincode: '', country: 'India' });
  const [showNewAddress, setShowNewAddress] = useState(false);
  const { cart, clearCart } = useCart();
  const navigate = useNavigate();

  useEffect(() => {
    userAPI.getAddresses().then(r => {
      setAddresses(r.data);
      if (r.data.length > 0) setSelectedAddress(r.data[0].id);
    }).catch(console.error);
  }, []);

  const handleAddAddress = async () => {
    try {
      const res = await userAPI.addAddress(newAddress);
      setAddresses(prev => [...prev, res.data]);
      setSelectedAddress(res.data.id);
      setShowNewAddress(false);
      toast.success('Address added!');
    } catch (err) {
      toast.error('Failed to add address');
    }
  };

  const handlePlaceOrder = async () => {
    if (!selectedAddress) { toast.error('Please select a delivery address'); return; }
    setLoading(true);
    try {
      const res = await orderAPI.placeOrder({ addressId: selectedAddress, paymentMethod });
      toast.success('Order placed successfully!');
      navigate(`/orders/${res.data.id}`);
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to place order');
    } finally {
      setLoading(false);
    }
  };

  const shippingFee = cart.totalAmount > 499 ? 0 : 49;

  return (
    <Container className="py-4">
      <h3 style={{ fontFamily: 'Syne, sans-serif', fontWeight: 800 }}>Checkout</h3>
      <Row className="g-4 mt-1">
        <Col lg={8}>
          {/* Delivery Address */}
          <div style={{ background: 'white', borderRadius: 'var(--nk-radius)', padding: '1.5rem', boxShadow: 'var(--nk-shadow)', marginBottom: '1.5rem' }}>
            <h5 style={{ fontFamily: 'Syne, sans-serif', fontWeight: 700 }}>📍 Delivery Address</h5>
            {addresses.map(addr => (
              <div key={addr.id} className="d-flex align-items-start gap-2 p-2 mb-2"
                style={{ border: selectedAddress === addr.id ? '2px solid var(--nk-primary)' : '2px solid #eee', borderRadius: 8, cursor: 'pointer' }}
                onClick={() => setSelectedAddress(addr.id)}>
                <input type="radio" checked={selectedAddress === addr.id} onChange={() => setSelectedAddress(addr.id)} />
                <div>
                  <strong>{addr.name}</strong> | {addr.phone}<br />
                  <small style={{ color: '#6c757d' }}>{addr.addressLine1}, {addr.city}, {addr.state} - {addr.pincode}</small>
                </div>
              </div>
            ))}
            <button onClick={() => setShowNewAddress(!showNewAddress)}
              style={{ background: 'none', border: '2px dashed #ccc', borderRadius: 8, padding: '0.5rem 1rem', cursor: 'pointer', color: 'var(--nk-primary)', fontWeight: 600, width: '100%', marginTop: '0.5rem' }}>
              + Add New Address
            </button>
            {showNewAddress && (
              <div className="mt-3">
                <Row className="g-2">
                  <Col sm={6}><Form.Control placeholder="Full Name" value={newAddress.name} onChange={e => setNewAddress(p => ({ ...p, name: e.target.value }))} /></Col>
                  <Col sm={6}><Form.Control placeholder="Phone" value={newAddress.phone} onChange={e => setNewAddress(p => ({ ...p, phone: e.target.value }))} /></Col>
                  <Col sm={12}><Form.Control placeholder="Address Line 1" value={newAddress.addressLine1} onChange={e => setNewAddress(p => ({ ...p, addressLine1: e.target.value }))} /></Col>
                  <Col sm={4}><Form.Control placeholder="City" value={newAddress.city} onChange={e => setNewAddress(p => ({ ...p, city: e.target.value }))} /></Col>
                  <Col sm={4}><Form.Control placeholder="State" value={newAddress.state} onChange={e => setNewAddress(p => ({ ...p, state: e.target.value }))} /></Col>
                  <Col sm={4}><Form.Control placeholder="Pincode" value={newAddress.pincode} onChange={e => setNewAddress(p => ({ ...p, pincode: e.target.value }))} /></Col>
                  <Col sm={12}><button className="btn-nk-primary" style={{ padding: '0.5rem 1.5rem' }} onClick={handleAddAddress}>Save Address</button></Col>
                </Row>
              </div>
            )}
          </div>

          {/* Payment Method */}
          <div style={{ background: 'white', borderRadius: 'var(--nk-radius)', padding: '1.5rem', boxShadow: 'var(--nk-shadow)' }}>
            <h5 style={{ fontFamily: 'Syne, sans-serif', fontWeight: 700 }}>💳 Payment Method</h5>
            {['COD', 'UPI', 'CARD', 'NET_BANKING'].map(pm => (
              <div key={pm} className="d-flex align-items-center gap-2 p-2 mb-2"
                style={{ border: paymentMethod === pm ? '2px solid var(--nk-primary)' : '2px solid #eee', borderRadius: 8, cursor: 'pointer' }}
                onClick={() => setPaymentMethod(pm)}>
                <input type="radio" checked={paymentMethod === pm} onChange={() => setPaymentMethod(pm)} />
                <span>{pm === 'COD' ? '💵 Cash on Delivery' : pm === 'UPI' ? '📱 UPI (GPay/PhonePe/Paytm)' : pm === 'CARD' ? '💳 Credit/Debit Card' : '🏦 Net Banking'}</span>
              </div>
            ))}
          </div>
        </Col>

        <Col lg={4}>
          <div style={{ background: 'white', borderRadius: 'var(--nk-radius)', padding: '1.5rem', boxShadow: 'var(--nk-shadow)', position: 'sticky', top: '80px' }}>
            <h5 style={{ fontFamily: 'Syne, sans-serif', fontWeight: 700, borderBottom: '2px solid #f0f0f0', paddingBottom: '0.75rem' }}>Order Summary</h5>
            {cart.items?.map(item => (
              <div key={item.id} className="d-flex justify-content-between mb-1" style={{ fontSize: '0.85rem' }}>
                <span>{item.productName} × {item.quantity}</span>
                <span>₹{Number(item.subtotal).toLocaleString('en-IN')}</span>
              </div>
            ))}
            <hr />
            <div className="d-flex justify-content-between mb-1"><span>Subtotal</span><span>₹{Number(cart.totalAmount).toLocaleString('en-IN')}</span></div>
            <div className="d-flex justify-content-between mb-2"><span>Delivery</span><span style={{ color: shippingFee === 0 ? 'green' : 'inherit' }}>{shippingFee === 0 ? 'FREE' : `₹${shippingFee}`}</span></div>
            <hr />
            <div className="d-flex justify-content-between mb-3" style={{ fontWeight: 700, fontSize: '1.1rem' }}>
              <span>Total</span>
              <span style={{ color: 'var(--nk-primary)', fontFamily: 'Syne, sans-serif' }}>₹{(Number(cart.totalAmount) + shippingFee).toLocaleString('en-IN')}</span>
            </div>
            <button className="btn-nk-primary w-100" onClick={handlePlaceOrder} disabled={loading}>
              {loading ? 'Placing Order...' : '✅ Place Order'}
            </button>
          </div>
        </Col>
      </Row>
    </Container>
  );
};

export default CheckoutPage;
